import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class BankingApp {

    public synchronized boolean processTransaction(String accountId, double transactionAmount) {
        Connection connection = null;
        PreparedStatement getBalanceStmt = null;
        PreparedStatement updateBalanceStmt = null;
        ResultSet rs = null;

        try {
            connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/bank", "user", "password");
            connection.setAutoCommit(false);

            String getBalanceQuery = "SELECT balance FROM accounts WHERE account_id = ?";
            getBalanceStmt = connection.prepareStatement(getBalanceQuery);
            getBalanceStmt.setString(1, accountId);
            rs = getBalanceStmt.executeQuery();

            if (rs.next()) {
                double currentBalance = rs.getDouble("balance");
                
                if (transactionAmount > currentBalance) {
                    return false; // Insufficient funds
                }
                
                String updateBalanceQuery = "UPDATE accounts SET balance = balance - ? WHERE account_id = ?";
                updateBalanceStmt = connection.prepareStatement(updateBalanceQuery);
                updateBalanceStmt.setDouble(1, transactionAmount);
                updateBalanceStmt.setString(2, accountId);
                updateBalanceStmt.executeUpdate();

                connection.commit();
                return true;
            }
            
            return false; // Account not found

        } catch (SQLException e) {
            if (connection != null) {
                try {
                    connection.rollback();
                } catch (SQLException ex) {
                    ex.printStackTrace();
                }
            }
            e.printStackTrace();
            return false;
        } finally {
            try {
                if (rs != null) rs.close();
                if (getBalanceStmt != null) getBalanceStmt.close();
                if (updateBalanceStmt != null) updateBalanceStmt.close();
                if (connection != null) connection.close();
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }
    }
}